--
-- Table structure for table `injuryrecord`
--

DROP TABLE IF EXISTS `injuryrecord`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `injuryrecord` (
  `injury_id` int NOT NULL AUTO_INCREMENT COMMENT '病例id（主键）',
  `patient_id` int NOT NULL COMMENT '患者id（外键）',
  `admission_date` date DEFAULT NULL COMMENT '接诊日期',
  `season` tinyint DEFAULT NULL COMMENT '季节（0-春季，1-夏季，2-秋季，3-冬季）',
  `admission_time` varchar(4) DEFAULT NULL COMMENT '接诊时间（四位数字格式，如1100）',
  `time_period` tinyint DEFAULT NULL COMMENT '时间段（0-凌晨0-4点，1-早晨4-8点，2-上午8-12点，3-下午12-16点，4-傍晚16-20点，5-晚上20-24点）',
  `arrival_method` varchar(100) DEFAULT NULL COMMENT '来院方式',
  `injury_location` varchar(500) DEFAULT NULL COMMENT '创伤发生地',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `station_name` varchar(200) DEFAULT NULL COMMENT '120分站站点名称',
  `injury_cause_category` tinyint DEFAULT NULL COMMENT '受伤原因分类（0-交通伤，1-高坠伤，2-机械伤，3-跌倒，4-其他）',
  `injury_cause_detail` varchar(200) DEFAULT NULL COMMENT '受伤原因具体描述（如：爆炸伤、玻璃划伤等）',
  PRIMARY KEY (`injury_id`),
  KEY `patient_id` (`patient_id`),
  KEY `idx_injury_cause_category` (`injury_cause_category`),
  KEY `idx_season` (`season`),
  KEY `idx_time_period` (`time_period`),
  CONSTRAINT `injuryrecord_ibfk_1` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`)
) ENGINE=InnoDB AUTO_INCREMENT=11997 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='病例发生记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

