--
-- Table structure for table `intervention_extra`
--

DROP TABLE IF EXISTS `intervention_extra`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `intervention_extra` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `patient_id` int NOT NULL COMMENT '患者id（外键）',
  `oxygen_concentration` float DEFAULT NULL COMMENT '氧浓度（百分比）',
  `defibrillation` varchar(5) DEFAULT NULL COMMENT '除颤（1是/0否）',
  `limb_amputation` varchar(5) DEFAULT NULL COMMENT '肢体离断（1是/0否）',
  `transfusion_reaction` varchar(200) DEFAULT NULL COMMENT '输血反应',
  `suspended_red_units` float DEFAULT NULL COMMENT '悬红',
  `plasma_units` float DEFAULT NULL COMMENT '血浆',
  `platelets_amount` float DEFAULT NULL COMMENT '血小板',
  `cryoprecipitate_units` float DEFAULT NULL COMMENT '冷沉淀',
  `other_transfusion` varchar(200) DEFAULT NULL COMMENT '其他',
  `therapeutic_operation` varchar(200) DEFAULT NULL COMMENT '治疗性操作',
  `consultation_dept` varchar(200) DEFAULT NULL COMMENT '会诊科室',
  `administrative_dept` varchar(200) DEFAULT NULL COMMENT '行政科室',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_patient` (`patient_id`),
  CONSTRAINT `fk_intervention_extra_patient` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`)
) ENGINE=InnoDB AUTO_INCREMENT=22828 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='干预过程补充表';
/*!40101 SET character_set_client = @saved_cs_client */;

