--
-- Table structure for table `patient_info_off_admission`
--

DROP TABLE IF EXISTS `patient_info_off_admission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `patient_info_off_admission` (
  `id` int NOT NULL AUTO_INCREMENT,
  `patient_id` int NOT NULL,
  `temperature` float DEFAULT NULL COMMENT '体温',
  `respiratory_rate` int DEFAULT NULL COMMENT '呼吸频率',
  `heart_rate` int DEFAULT NULL COMMENT '心率',
  `systolic_bp` int DEFAULT NULL COMMENT '血压高压',
  `diastolic_bp` int DEFAULT NULL COMMENT '血压低压',
  `oxygen_saturation` float DEFAULT NULL COMMENT '指脉氧',
  `total_fluid_volume` float DEFAULT NULL COMMENT '总补液量',
  `saline_solution` float DEFAULT NULL COMMENT '生理盐水',
  `balanced_solution` float DEFAULT NULL COMMENT '平衡液',
  `artificial_colloid` float DEFAULT NULL COMMENT '人工胶体',
  `other_fluid` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '其他补液',
  `urine_output` float DEFAULT NULL COMMENT '尿量',
  `other_drainage` float DEFAULT NULL COMMENT '其他引流量',
  `blood_loss` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '出血量',
  PRIMARY KEY (`id`),
  KEY `patient_id` (`patient_id`),
  CONSTRAINT `patient_info_off_admission_ibfk_1` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=20677 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='患者离开时信息表';
