DROP TABLE IF EXISTS `patient_info_on_admission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `patient_info_on_admission` (
  `id` int NOT NULL AUTO_INCREMENT,
  `patient_id` int NOT NULL,
  `systolic_bp` int DEFAULT '0' COMMENT '血压高压',
  `diastolic_bp` int DEFAULT '0' COMMENT '血压低压',
  `heart_rate` int DEFAULT '0' COMMENT '心率',
  `respiratory_rate` int DEFAULT '0' COMMENT '呼吸频率',
  `medical_history` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '既往病史',
  `temperature` float DEFAULT '0' COMMENT '入室温度',
  `oxygen_saturation` int DEFAULT '0' COMMENT '指脉氧',
  `consciousness` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '精神意识',
  `skin` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '皮肤',
  `drunk` tinyint(1) DEFAULT '0' COMMENT '醉酒',
  `pupil` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '瞳孔',
  `light_reflex` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '对光反射',
  PRIMARY KEY (`id`),
  KEY `patient_id` (`patient_id`),
  CONSTRAINT `patient_info_on_admission_ibfk_1` FOREIGN KEY (`patient_id`) REFERENCES `patient` (`patient_id`)
) ENGINE=InnoDB AUTO_INCREMENT=20686 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
